; Function Attrs: nounwind
define void @memcpy_32(ptr %dst, ptr %src) #0 !prof !0 {
  call void @llvm.memcpy.inline.p0.p0.i64(ptr %dst, ptr %src, i64 32, i1 false), !prof !1
  tail call void @llvm.memcpy.inline.p0.p0.i64(ptr %dst, ptr %src, i64 32, i1 true)
  ret void
}

; Function Attrs: nocallback nofree nounwind willreturn memory(argmem: readwrite)
declare void @llvm.memcpy.inline.p0.p0.i64(ptr noalias nocapture writeonly, ptr noalias nocapture readonly, i64, i1 immarg) #1

attributes #0 = { nounwind }
attributes #1 = { nocallback nofree nounwind willreturn memory(argmem: readwrite) }

!0 = !{!"function_entry_count", i32 10}
!1 = !{!"VP", i32 1, i32 100, i32 5, i32 10, i32 16, i32 13}

; Function Attrs: nounwind
define void @memcpy_x(ptr %dst, ptr %src, i64 %x) #0 !prof !0 {
  call void @llvm.memcpy.inline.p0.p0.i64(ptr %dst, ptr %src, i64 %x, i1 false)
  tail call void @llvm.memcpy.inline.p0.p0.i64(ptr %dst, ptr %src, i64 %x, i1 true), !prof !1
  ret void
}

